/**
 * Unit tests for Workspace & Team Management Engine
 */
import {
  getPermissions,
  hasPermission,
  canPerformAction,
  canChangeRole,
  validateWorkspace,
  validateInvitation,
  generateSlug,
  isInvitationExpired,
  getMembersByRole,
  getActiveMembers,
  isAtMemberLimit,
  isAtProjectLimit,
  formatMemberSince,
  getRoleLabel,
  getRoleBadgeColor,
  ROLE_PERMISSIONS,
  PLAN_LIMITS,
  type Workspace,
  type WorkspaceMember,
  type WorkspaceInvitation,
  type WorkspaceRole,
  type PermissionSet,
} from '@/lib/workspace/workspace-manager';

// ─── Helpers ─────────────────────────────────────────────────────────

function makeWorkspace(overrides?: Partial<Workspace>): Workspace {
  return {
    id: 'ws-1',
    name: 'Test Workspace',
    slug: 'test-workspace',
    description: 'A test workspace',
    ownerId: 'user-1',
    plan: 'pro',
    maxMembers: 10,
    maxProjects: 50,
    createdAt: '2025-01-01T00:00:00Z',
    updatedAt: '2025-01-01T00:00:00Z',
    ...overrides,
  };
}

function makeMember(overrides?: Partial<WorkspaceMember>): WorkspaceMember {
  return {
    id: 'member-1',
    workspaceId: 'ws-1',
    userId: 'user-1',
    email: 'user@test.com',
    name: 'Test User',
    role: 'editor',
    joinedAt: '2025-01-01T00:00:00Z',
    invitedBy: 'user-0',
    status: 'active',
    ...overrides,
  };
}

function makeInvitation(overrides?: Partial<WorkspaceInvitation>): WorkspaceInvitation {
  return {
    id: 'inv-1',
    workspaceId: 'ws-1',
    email: 'new@test.com',
    role: 'editor',
    invitedBy: 'user-1',
    expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
    token: 'token-abc',
    status: 'pending',
    createdAt: new Date().toISOString(),
    ...overrides,
  };
}

// ─── Tests ───────────────────────────────────────────────────────────

describe('Workspace Manager', () => {
  // ── getPermissions ────────────────────────────────────────────────

  describe('getPermissions', () => {
    it('should return all true for owner', () => {
      const perms = getPermissions('owner');
      const allKeys = Object.keys(perms) as Array<keyof PermissionSet>;
      allKeys.forEach((key) => {
        expect(perms[key]).toBe(true);
      });
    });

    it('should return correct permissions for admin', () => {
      const perms = getPermissions('admin');
      expect(perms.canViewProjects).toBe(true);
      expect(perms.canEditProjects).toBe(true);
      expect(perms.canDeleteProjects).toBe(true);
      expect(perms.canInviteMembers).toBe(true);
      expect(perms.canRemoveMembers).toBe(true);
      expect(perms.canChangeRoles).toBe(true);
      expect(perms.canEditWorkspace).toBe(true);
      expect(perms.canDeleteWorkspace).toBe(false);
      expect(perms.canManageBilling).toBe(false);
    });

    it('should return correct permissions for editor', () => {
      const perms = getPermissions('editor');
      expect(perms.canViewProjects).toBe(true);
      expect(perms.canEditProjects).toBe(true);
      expect(perms.canDeleteProjects).toBe(false);
      expect(perms.canInviteMembers).toBe(false);
      expect(perms.canRemoveMembers).toBe(false);
      expect(perms.canChangeRoles).toBe(false);
      expect(perms.canEditWorkspace).toBe(false);
    });

    it('should return correct permissions for viewer', () => {
      const perms = getPermissions('viewer');
      expect(perms.canViewProjects).toBe(true);
      expect(perms.canEditProjects).toBe(false);
      expect(perms.canDeleteProjects).toBe(false);
      expect(perms.canInviteMembers).toBe(false);
      expect(perms.canRemoveMembers).toBe(false);
      expect(perms.canChangeRoles).toBe(false);
      expect(perms.canEditWorkspace).toBe(false);
      expect(perms.canDeleteWorkspace).toBe(false);
      expect(perms.canManageBilling).toBe(false);
    });

    it('should return a copy (not leak internal state)', () => {
      const perms = getPermissions('owner');
      perms.canViewProjects = false;
      expect(getPermissions('owner').canViewProjects).toBe(true);
    });
  });

  // ── hasPermission ─────────────────────────────────────────────────

  describe('hasPermission', () => {
    it('owner should have all permissions', () => {
      expect(hasPermission('owner', 'canDeleteWorkspace')).toBe(true);
      expect(hasPermission('owner', 'canManageBilling')).toBe(true);
      expect(hasPermission('owner', 'canViewProjects')).toBe(true);
    });

    it('viewer should only have canViewProjects', () => {
      expect(hasPermission('viewer', 'canViewProjects')).toBe(true);
      expect(hasPermission('viewer', 'canEditProjects')).toBe(false);
      expect(hasPermission('viewer', 'canInviteMembers')).toBe(false);
      expect(hasPermission('viewer', 'canDeleteWorkspace')).toBe(false);
    });

    it('editor should have view and edit but not delete projects', () => {
      expect(hasPermission('editor', 'canViewProjects')).toBe(true);
      expect(hasPermission('editor', 'canEditProjects')).toBe(true);
      expect(hasPermission('editor', 'canDeleteProjects')).toBe(false);
    });
  });

  // ── canPerformAction ──────────────────────────────────────────────

  describe('canPerformAction', () => {
    it('owner can perform all actions', () => {
      expect(canPerformAction('owner', 'view_project')).toBe(true);
      expect(canPerformAction('owner', 'delete_workspace')).toBe(true);
      expect(canPerformAction('owner', 'manage_billing')).toBe(true);
    });

    it('admin cannot delete workspace or manage billing', () => {
      expect(canPerformAction('admin', 'invite_member')).toBe(true);
      expect(canPerformAction('admin', 'delete_workspace')).toBe(false);
      expect(canPerformAction('admin', 'manage_billing')).toBe(false);
    });

    it('editor can view and edit projects only', () => {
      expect(canPerformAction('editor', 'view_project')).toBe(true);
      expect(canPerformAction('editor', 'edit_project')).toBe(true);
      expect(canPerformAction('editor', 'delete_project')).toBe(false);
      expect(canPerformAction('editor', 'invite_member')).toBe(false);
    });

    it('viewer can only view projects', () => {
      expect(canPerformAction('viewer', 'view_project')).toBe(true);
      expect(canPerformAction('viewer', 'edit_project')).toBe(false);
      expect(canPerformAction('viewer', 'remove_member')).toBe(false);
    });
  });

  // ── canChangeRole ─────────────────────────────────────────────────

  describe('canChangeRole', () => {
    it('owner can promote editor to admin', () => {
      expect(canChangeRole('owner', 'editor', 'admin')).toBe(true);
    });

    it('owner can demote admin to editor', () => {
      expect(canChangeRole('owner', 'admin', 'editor')).toBe(true);
    });

    it('owner can change viewer to editor', () => {
      expect(canChangeRole('owner', 'viewer', 'editor')).toBe(true);
    });

    it('admin cannot promote editor to admin', () => {
      expect(canChangeRole('admin', 'editor', 'admin')).toBe(false);
    });

    it('admin cannot demote another admin', () => {
      expect(canChangeRole('admin', 'admin', 'editor')).toBe(false);
    });

    it('admin can change viewer to editor', () => {
      expect(canChangeRole('admin', 'viewer', 'editor')).toBe(true);
    });

    it('editor cannot change any roles', () => {
      expect(canChangeRole('editor', 'viewer', 'editor')).toBe(false);
    });

    it('viewer cannot change any roles', () => {
      expect(canChangeRole('viewer', 'editor', 'admin')).toBe(false);
    });

    it('cannot promote anyone to owner', () => {
      expect(canChangeRole('owner', 'admin', 'owner')).toBe(false);
    });

    it('cannot change to the same role', () => {
      expect(canChangeRole('owner', 'editor', 'editor')).toBe(false);
    });

    it('cannot change owner role', () => {
      expect(canChangeRole('admin', 'owner', 'editor')).toBe(false);
    });
  });

  // ── validateWorkspace ─────────────────────────────────────────────

  describe('validateWorkspace', () => {
    it('should return no errors for valid workspace', () => {
      const errors = validateWorkspace({
        name: 'My Workspace',
        slug: 'my-workspace',
        description: 'A description',
      });
      expect(errors).toEqual([]);
    });

    it('should error on missing name', () => {
      const errors = validateWorkspace({ slug: 'my-ws', description: '' });
      expect(errors).toContain('Nome deve ter pelo menos 2 caracteres');
    });

    it('should error on short name', () => {
      const errors = validateWorkspace({ name: 'A', slug: 'aaa' });
      expect(errors).toContain('Nome deve ter pelo menos 2 caracteres');
    });

    it('should error on long name', () => {
      const errors = validateWorkspace({ name: 'A'.repeat(51), slug: 'aaa' });
      expect(errors).toContain('Nome deve ter no máximo 50 caracteres');
    });

    it('should error on short slug', () => {
      const errors = validateWorkspace({ name: 'OK', slug: 'ab' });
      expect(errors).toContain('Slug deve ter pelo menos 3 caracteres');
    });

    it('should error on long slug', () => {
      const errors = validateWorkspace({ name: 'OK', slug: 'a'.repeat(31) });
      expect(errors).toContain('Slug deve ter no máximo 30 caracteres');
    });

    it('should error on invalid slug chars', () => {
      const errors = validateWorkspace({ name: 'OK', slug: 'My Slug!' });
      expect(errors).toContain('Slug deve conter apenas letras minúsculas, números e hífens');
    });

    it('should error on long description', () => {
      const errors = validateWorkspace({
        name: 'OK',
        slug: 'ok-slug',
        description: 'D'.repeat(201),
      });
      expect(errors).toContain('Descrição deve ter no máximo 200 caracteres');
    });

    it('should allow empty description', () => {
      const errors = validateWorkspace({
        name: 'OK',
        slug: 'ok-slug',
        description: '',
      });
      expect(errors).toEqual([]);
    });
  });

  // ── validateInvitation ────────────────────────────────────────────

  describe('validateInvitation', () => {
    const workspace = makeWorkspace();
    const existingMembers = [
      makeMember({ email: 'existing@test.com', userId: 'user-1' }),
    ];

    it('should return no errors for valid invitation', () => {
      const errors = validateInvitation(
        makeInvitation({ email: 'new@test.com', role: 'editor' }),
        workspace,
        existingMembers,
      );
      expect(errors).toEqual([]);
    });

    it('should error on already existing member', () => {
      const errors = validateInvitation(
        makeInvitation({ email: 'existing@test.com' }),
        workspace,
        existingMembers,
      );
      expect(errors).toContain('Usuário já é membro deste workspace');
    });

    it('should error when at member limit', () => {
      const fullWorkspace = makeWorkspace({ maxMembers: 1 });
      const errors = validateInvitation(
        makeInvitation({ email: 'new@test.com' }),
        fullWorkspace,
        existingMembers,
      );
      expect(errors.some((e) => e.includes('Limite de'))).toBe(true);
    });

    it('should error on invalid email', () => {
      const errors = validateInvitation(
        makeInvitation({ email: 'not-an-email' }),
        workspace,
        existingMembers,
      );
      expect(errors).toContain('Email inválido');
    });

    it('should error on missing email', () => {
      const errors = validateInvitation(
        { role: 'editor', invitedBy: 'user-1' } as Partial<WorkspaceInvitation>,
        workspace,
        existingMembers,
      );
      expect(errors).toContain('Email inválido');
    });

    it('should error on invalid role', () => {
      const errors = validateInvitation(
        makeInvitation({ role: 'superadmin' as WorkspaceRole }),
        workspace,
        existingMembers,
      );
      expect(errors).toContain('Role inválida');
    });

    it('should error when inviting self', () => {
      const errors = validateInvitation(
        makeInvitation({ email: 'existing@test.com', invitedBy: 'user-1' }),
        workspace,
        existingMembers,
      );
      expect(errors).toContain('Não é possível convidar a si mesmo');
    });
  });

  // ── generateSlug ──────────────────────────────────────────────────

  describe('generateSlug', () => {
    it('should convert name to slug', () => {
      expect(generateSlug('My Workspace')).toBe('my-workspace');
    });

    it('should handle spaces', () => {
      expect(generateSlug('Hello World Test')).toBe('hello-world-test');
    });

    it('should remove special characters', () => {
      expect(generateSlug('Test!!!Space@#$')).toBe('testspace');
    });

    it('should truncate to 30 chars', () => {
      const longName = 'This Is A Very Long Workspace Name That Exceeds Thirty Characters';
      expect(generateSlug(longName).length).toBeLessThanOrEqual(30);
    });

    it('should handle already lowercase', () => {
      expect(generateSlug('simple')).toBe('simple');
    });

    it('should handle multiple hyphens', () => {
      expect(generateSlug('test   multiple   spaces')).toBe('test-multiple-spaces');
    });
  });

  // ── isInvitationExpired ───────────────────────────────────────────

  describe('isInvitationExpired', () => {
    it('should return false for future expiration', () => {
      const invitation = makeInvitation({
        expiresAt: new Date(Date.now() + 86400000).toISOString(),
      });
      expect(isInvitationExpired(invitation)).toBe(false);
    });

    it('should return true for past expiration', () => {
      const invitation = makeInvitation({
        expiresAt: new Date(Date.now() - 86400000).toISOString(),
      });
      expect(isInvitationExpired(invitation)).toBe(true);
    });

    it('should return true for exactly now (edge case)', () => {
      const invitation = makeInvitation({
        expiresAt: new Date(Date.now() - 1).toISOString(),
      });
      expect(isInvitationExpired(invitation)).toBe(true);
    });
  });

  // ── getMembersByRole ──────────────────────────────────────────────

  describe('getMembersByRole', () => {
    const members: WorkspaceMember[] = [
      makeMember({ id: '1', role: 'owner', email: 'owner@test.com' }),
      makeMember({ id: '2', role: 'editor', email: 'editor1@test.com' }),
      makeMember({ id: '3', role: 'editor', email: 'editor2@test.com' }),
      makeMember({ id: '4', role: 'viewer', email: 'viewer@test.com' }),
    ];

    it('should return only editors', () => {
      const editors = getMembersByRole(members, 'editor');
      expect(editors).toHaveLength(2);
      expect(editors.every((m) => m.role === 'editor')).toBe(true);
    });

    it('should return only owner', () => {
      const owners = getMembersByRole(members, 'owner');
      expect(owners).toHaveLength(1);
      expect(owners[0].role).toBe('owner');
    });

    it('should return empty for non-existent role members', () => {
      const admins = getMembersByRole(members, 'admin');
      expect(admins).toHaveLength(0);
    });
  });

  // ── getActiveMembers ──────────────────────────────────────────────

  describe('getActiveMembers', () => {
    it('should filter out invited and suspended members', () => {
      const members: WorkspaceMember[] = [
        makeMember({ id: '1', status: 'active' }),
        makeMember({ id: '2', status: 'invited' }),
        makeMember({ id: '3', status: 'suspended' }),
        makeMember({ id: '4', status: 'active' }),
      ];
      const active = getActiveMembers(members);
      expect(active).toHaveLength(2);
      expect(active.every((m) => m.status === 'active')).toBe(true);
    });

    it('should return empty for no active members', () => {
      const members: WorkspaceMember[] = [
        makeMember({ id: '1', status: 'invited' }),
        makeMember({ id: '2', status: 'suspended' }),
      ];
      expect(getActiveMembers(members)).toHaveLength(0);
    });
  });

  // ── isAtMemberLimit ───────────────────────────────────────────────

  describe('isAtMemberLimit', () => {
    it('should return false when under limit', () => {
      const ws = makeWorkspace({ maxMembers: 10 });
      expect(isAtMemberLimit(ws, 5)).toBe(false);
    });

    it('should return true when at limit', () => {
      const ws = makeWorkspace({ maxMembers: 10 });
      expect(isAtMemberLimit(ws, 10)).toBe(true);
    });

    it('should return true when over limit', () => {
      const ws = makeWorkspace({ maxMembers: 10 });
      expect(isAtMemberLimit(ws, 15)).toBe(true);
    });
  });

  // ── isAtProjectLimit ──────────────────────────────────────────────

  describe('isAtProjectLimit', () => {
    it('should return false when under limit', () => {
      const ws = makeWorkspace({ maxProjects: 50 });
      expect(isAtProjectLimit(ws, 10)).toBe(false);
    });

    it('should return true when at limit', () => {
      const ws = makeWorkspace({ maxProjects: 50 });
      expect(isAtProjectLimit(ws, 50)).toBe(true);
    });
  });

  // ── formatMemberSince ─────────────────────────────────────────────

  describe('formatMemberSince', () => {
    it('should return "hoje" for today', () => {
      expect(formatMemberSince(new Date().toISOString())).toBe('hoje');
    });

    it('should return "há 1 dia" for yesterday', () => {
      const yesterday = new Date(Date.now() - 86400000 * 1.5).toISOString();
      expect(formatMemberSince(yesterday)).toBe('há 1 dia');
    });

    it('should return "há X dias" for recent dates', () => {
      const fiveDaysAgo = new Date(Date.now() - 86400000 * 5).toISOString();
      expect(formatMemberSince(fiveDaysAgo)).toBe('há 5 dias');
    });

    it('should return "há 1 mês" for 30+ days', () => {
      const thirtyDaysAgo = new Date(Date.now() - 86400000 * 35).toISOString();
      expect(formatMemberSince(thirtyDaysAgo)).toBe('há 1 mês');
    });

    it('should return "há X meses" for multiple months', () => {
      const threeMonthsAgo = new Date(Date.now() - 86400000 * 100).toISOString();
      expect(formatMemberSince(threeMonthsAgo)).toBe('há 3 meses');
    });

    it('should return "há 1 ano" for 12+ months', () => {
      const oneYearAgo = new Date(Date.now() - 86400000 * 400).toISOString();
      expect(formatMemberSince(oneYearAgo)).toBe('há 1 ano');
    });
  });

  // ── getRoleLabel ──────────────────────────────────────────────────

  describe('getRoleLabel', () => {
    it('should return "Proprietário" for owner', () => {
      expect(getRoleLabel('owner')).toBe('Proprietário');
    });

    it('should return "Administrador" for admin', () => {
      expect(getRoleLabel('admin')).toBe('Administrador');
    });

    it('should return "Editor" for editor', () => {
      expect(getRoleLabel('editor')).toBe('Editor');
    });

    it('should return "Visualizador" for viewer', () => {
      expect(getRoleLabel('viewer')).toBe('Visualizador');
    });
  });

  // ── getRoleBadgeColor ─────────────────────────────────────────────

  describe('getRoleBadgeColor', () => {
    it('should return amber classes for owner', () => {
      expect(getRoleBadgeColor('owner')).toContain('amber');
    });

    it('should return purple classes for admin', () => {
      expect(getRoleBadgeColor('admin')).toContain('purple');
    });

    it('should return blue classes for editor', () => {
      expect(getRoleBadgeColor('editor')).toContain('blue');
    });

    it('should return gray classes for viewer', () => {
      expect(getRoleBadgeColor('viewer')).toContain('gray');
    });
  });

  // ── ROLE_PERMISSIONS completeness ─────────────────────────────────

  describe('ROLE_PERMISSIONS', () => {
    const allRoles: WorkspaceRole[] = ['owner', 'admin', 'editor', 'viewer'];
    const allPermKeys: Array<keyof PermissionSet> = [
      'canViewProjects',
      'canEditProjects',
      'canDeleteProjects',
      'canInviteMembers',
      'canRemoveMembers',
      'canChangeRoles',
      'canEditWorkspace',
      'canDeleteWorkspace',
      'canManageBilling',
    ];

    it('should define permissions for all 4 roles', () => {
      allRoles.forEach((role) => {
        expect(ROLE_PERMISSIONS[role]).toBeDefined();
      });
    });

    it('every role should have all permission keys', () => {
      allRoles.forEach((role) => {
        allPermKeys.forEach((key) => {
          expect(typeof ROLE_PERMISSIONS[role][key]).toBe('boolean');
        });
      });
    });
  });

  // ── PLAN_LIMITS ───────────────────────────────────────────────────

  describe('PLAN_LIMITS', () => {
    it('free plan should have 3 members and 5 projects', () => {
      expect(PLAN_LIMITS.free.maxMembers).toBe(3);
      expect(PLAN_LIMITS.free.maxProjects).toBe(5);
    });

    it('pro plan should have 10 members and 50 projects', () => {
      expect(PLAN_LIMITS.pro.maxMembers).toBe(10);
      expect(PLAN_LIMITS.pro.maxProjects).toBe(50);
    });

    it('business plan should have 50 members and 9999 projects', () => {
      expect(PLAN_LIMITS.business.maxMembers).toBe(50);
      expect(PLAN_LIMITS.business.maxProjects).toBe(9999);
    });
  });
});
